# Python 3
n = int(input("Ingrese N: "))
print("Números primos entre 2 y", str(n) + ":")
for i in range(2, n + 1):
    es_primo = True
    for j in range(2, i):
        if i % j == 0:
            es_primo = False
            break
    if es_primo:
        print(i)
